def extract_span(text, start):
    # find the earliest of decorative bracket start or square bracket or newline
    # but include until decorative closing bracket if present right before
    # We'll stop at the decorative closing bracket '﴾' if present, or before '['
    # Find position of '﴾' after start
    candidates = []
    for ch in ["﴾", "[", "(", "، قال", "\n"]:
        idx = text.find(ch, start)
        if idx != -1:
            candidates.append(idx)
    if candidates:
        end = min(candidates)
    else:
        end = len(text)
    # If end is at '﴾', exclude it
    if text[end:end+1] == "﴾":
        return (start, end, text[start:end])
    else:
        return (start, end, text[start:end])
